ALGORITHM GPUKernelExecution
INPUT: n (number of elements), dataA, dataB
OUTPUT: result

// Step 1: Define Kernel Function
FUNCTION vectorAddKernel(A, B, C, n)
 // Calculate global thread index
 i = (blockIdx.x * blockDim.x) + threadIdx.x

 // Check boundary to avoid out-of-bounds access
 IF i < n THEN
 // Each thread performs one element operation
 C[i] = A[i] + B[i]
 END IF
END FUNCTION

// Step 2: Main Program
BEGIN
 // Step 2a: Allocate memory on host (CPU)
 hostA = allocate(n)
 hostB = allocate(n)
 hostC = allocate(n)

 // Step 2b: Initialize input data
 FOR i = 0 TO n-1 DO
 hostA[i] = i * 1.0
 hostB[i] = i * 2.0
 END FOR

 // Step 2c: Allocate memory on device (GPU)
 deviceA = deviceAllocate(n)
 deviceB = deviceAllocate(n)
 deviceC = deviceAllocate(n)

 // Step 2d: Copy data from host to device
 copyHostToDevice(deviceA, hostA)
 copyHostToDevice(deviceB, hostB)

 // Step 2e: Configure thread hierarchy
 threadsPerBlock = 256
 blocksPerGrid = ceiling(n / threadsPerBlock)

 // Step 2f: Launch kernel on GPU
 LAUNCH_KERNEL vectorAddKernel <<<blocksPerGrid, threadsPerBlock>>> (deviceA, deviceB, deviceC, n)

 // Step 2g: Wait for kernel completion
 synchronize()

 // Step 2h: Copy results from device to host
 copyDeviceToHost(hostC, deviceC)

 // Step 2i: Free all allocated memory
 freeHost(hostA, hostB, hostC)
 freeDevice(deviceA, deviceB, deviceC)

 OUTPUT hostC
END

/*
 * GPU Vector Addition - CUDA C Implementation
 * Demonstrates complete GPU programming workflow
 */

#include <stdio.h>
#include <stdlib.h>
#include <cuda_runtime.h>

// Error checking macro for CUDA operations
#define CUDA_CHECK(call) \
 do { \
 cudaError_t err = call; \
 if (err != cudaSuccess) { \
 fprintf(stderr, "CUDA error at %s:%d: %s\n", \
 __FILE__, __LINE__, cudaGetErrorString(err)); \
 exit(EXIT_FAILURE); \
 } \
 } while(0)

// GPU Kernel: Vector Addition
// Each thread computes one element of the result
__global__ void vectorAddKernel(const float *A, const float *B, float *C, int n) {
 // Calculate global thread index
 int idx = blockIdx.x * blockDim.x + threadIdx.x;

 // Boundary check - avoid out-of-bounds access
 if (idx < n) {
 C[idx] = A[idx] + B[idx];
 }
}

// Verify results on CPU
void verifyResults(const float *A, const float *B, const float *C, int n) {
 printf("Verifying first 10 results:\n");
 for (int i = 0; i < 10 && i < n; i++) {
 printf(" [%3d]: %6.2f + %6.2f = %6.2f (expected: %6.2f) %s\n",
 i, A[i], B[i], C[i], A[i] + B[i],
 (C[i] == A[i] + B[i]) ? "✓" : "✗");
 }
}

int main(int argc, char *argv[]) {
 int n = 1000000; // Number of elements

 // Default values for thread configuration
 int threadsPerBlock = 256;
 int blocksPerGrid = (n + threadsPerBlock - 1) / threadsPerBlock;

 printf("========================================\n");
 printf("GPU Vector Addition - CUDA Program\n");
 printf("========================================\n");
 printf("Vector size: %d elements\n", n);
 printf("Threads per block: %d\n", threadsPerBlock);
 printf("Blocks per grid: %d\n", blocksPerGrid);
 printf("Total threads: %d\n", blocksPerGrid * threadsPerBlock);
 printf("========================================\n\n");

 // Step 1: Allocate memory on host (CPU)
 float *h_A = (float *)malloc(n * sizeof(float));
 float *h_B = (float *)malloc(n * sizeof(float));
 float *h_C = (float *)malloc(n * sizeof(float));

 if (!h_A || !h_B || !h_C) {
 fprintf(stderr, "Failed to allocate host memory\n");
 return 1;
 }

 // Step 2: Initialize input vectors
 for (int i = 0; i < n; i++) {
 h_A[i] = (float)i;
 h_B[i] = (float)(i * 2);
 }

 // Step 3: Allocate memory on device (GPU)
 float *d_A, *d_B, *d_C;
 CUDA_CHECK(cudaMalloc((void **)&d_A, n * sizeof(float)));
 CUDA_CHECK(cudaMalloc((void **)&d_B, n * sizeof(float)));
 CUDA_CHECK(cudaMalloc((void **)&d_C, n * sizeof(float)));

 // Step 4: Copy input data from host to device
 CUDA_CHECK(cudaMemcpy(d_A, h_A, n * sizeof(float), cudaMemcpyHostToDevice));
 CUDA_CHECK(cudaMemcpy(d_B, h_B, n * sizeof(float), cudaMemcpyHostToDevice));

 // Step 5: Launch GPU kernel
 printf("Launching kernel with %d blocks, %d threads per block...\n",
 blocksPerGrid, threadsPerBlock);

 vectorAddKernel<<<blocksPerGrid, threadsPerBlock>>>(d_A, d_B, d_C, n);

 // Check for kernel launch errors
 CUDA_CHECK(cudaGetLastError());

 // Step 6: Wait for kernel completion and check errors
 CUDA_CHECK(cudaDeviceSynchronize());

 printf("Kernel execution completed!\n\n");

 // Step 7: Copy results from device to host
 CUDA_CHECK(cudaMemcpy(h_C, d_C, n * sizeof(float), cudaMemcpyDeviceToHost));

 // Step 8: Verify results
 verifyResults(h_A, h_B, h_C, n);

 // Step 9: Free all allocated memory
 free(h_A);
 free(h_B);
 free(h_C);
 CUDA_CHECK(cudaFree(d_A));
 CUDA_CHECK(cudaFree(d_B));
 CUDA_CHECK(cudaFree(d_C));

 printf("\n========================================\n");
 printf("Program completed successfully!\n");
 printf("========================================\n");

 return 0;
}
